body.--color-base-30:
hsl(
		from var(--background-secondary) h calc(s + 3) calc(l + 4)
	)

body.--text-highlight-bg:
hsl(
		from var(--attribute-psionic) calc(h + 20) calc(s - 10) l / 0.85
	)

body.styled-scrollbars.--color-base-30:
hsl(
		from var(--background-secondary) h calc(s + 3) calc(l + 4)
	)

body.styled-scrollbars.--text-highlight-bg:
hsl(
		from var(--attribute-psionic) calc(h + 20) calc(s - 10) l / 0.85
	)

h1[data-heading=\"This is a heading 1\"].background-color:
color-mix(
		in srgb,
		var(--heading-bg-modifier) var(--heading-bg-op),
		transparent
	)

h2[data-heading=\"This is a heading 2\"].--heading-bg-modifier:
hsl(
		from var(--C-Korazu_Orange) h calc(s + 90) l / 1
	)

